array.string:
PASS=$(security find-generic-password -s "ad4m-mcp" -a "passphrase" -w 2>/dev/null);
if [ -z "$PASS" ]; then exit 0; fi;
curl -s __GQL__ \
  -H "Content-Type: application/json" \
  -d "{\"query\":\"mutation { agentUnlock(passphrase: \\\"${PASS}\\\") { isUnlocked } }\"}" \
  >> __HOME__/.ad4m/auto-unlock.log 2>&1
